      setResolvedSrc(undefined)
      return () => {
        cancelled = true
      }
    }

    if (!src.startsWith("uploads/")) {
      setResolvedSrc(src)
      return () => {
        cancelled = true
      }
    }

    setResolvedSrc(undefined)
    void getSignedDownloadUrl(src)
      .then((url) => {
        if (cancelled) return
        setResolvedSrc(url)
      })
      .catch(() => {
        if (cancelled) return
        setResolvedSrc(undefined)
      })

    return () => {
      cancelled = true
    }
  }, [src])

  return (
    <AvatarPrimitive.Image
      data-slot="avatar-image"
      className={cn(
        "aspect-square size-full rounded-full object-cover",
        className
      )}
      src={resolvedSrc}
      {...props}
    />
  )
}

